let score;          // undefined — not yet assigned
score = null;       // null — explicitly empty

function greet(name) {
  console.log(name); // undefined if called as greet()
}

const obj = { a: 1 };
console.log(obj.b); // undefined — property doesn't exist

// React example: user starts as null (no user loaded yet)
const [user, setUser] = useState(null);
// After loading: setUser({ id: 1, name: 'Alice' })

// Primitives — copied by value
let a = 5;
let b = a;  // b gets a COPY of 5
b = 10;
console.log(a); // 5 — unchanged

// Objects — copied by reference
const obj1 = { count: 0 };
const obj2 = obj1; // obj2 points to the SAME object
obj2.count = 99;
console.log(obj1.count); // 99 — obj1 was also changed!

// ❌ Mutating state — React won't re-render because the reference is the same
state.count = state.count + 1;
setState(state); // same object reference!

// ✅ Creating a new object — React detects the change
setState({ ...state, count: state.count + 1 }); // new reference

// ❌ When count is 0, JSX renders the number 0 (falsy but JSX displays it)
function Cart({ count }) {
  return <div>{count && <Badge count={count} />}</div>;
}
// If count === 0 → renders <div>0</div> (visible "0" text on screen)

// ✅ Use an explicit boolean check
function Cart({ count }) {
  return <div>{count > 0 && <Badge count={count} />}</div>;
  // OR
  return <div>{count !== 0 && <Badge count={count} />}</div>;
}

// Input values are always strings
function AgeCheck() {
  const [age, setAge] = useState('');

  function check() {
    // ❌ '18' > 17 is true (coercion), but may surprise you
    // ✅ Always parse explicitly
    const parsed = Number(age);
    if (Number.isNaN(parsed)) {
      alert('Please enter a valid number');
      return;
    }
    if (parsed >= 18) {
      alert('Adult');
    }
  }

  return <input type="text" value={age} onChange={e => setAge(e.target.value)} />;
}
